-- ── Bugcrowd ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bugcrowd is a crowdsourced cybersecurity platform that connects organizations with a global network of vetted security researchers to run bug bounty, vulnerability disclosure, penetration-testing-as-a-service, and attack surface management programs.$q$, short_description),
  pricing_model = COALESCE($q$Custom, quote-based enterprise pricing; no public self-serve price list$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing; industry estimates put entry-level vulnerability disclosure programs around $10,000 per year and managed PTaaS retainers from roughly $25,000 per year, though Bugcrowd does not publish official rates$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (founded in Sydney, Australia)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bugcrowd Review 2026: Bug Bounty and PTaaS Platform Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$What Bugcrowd does, how its bug bounty, PTaaS and attack surface management platform works, current funding and ownership status, pricing model, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bugcrowd is one of the two largest crowdsourced cybersecurity platforms in the world, founded in 2012 in Sydney, Australia by Casey Ellis, Chris Raethke, and Sergei Belokamen, and now headquartered in San Francisco with additional offices in Sydney and London. The company's core idea is to connect organizations with a global, vetted network of independent security researchers who hunt for vulnerabilities in exchange for monetary rewards, replacing or augmenting traditional in-house penetration testing with continuous, crowd-powered coverage. Bugcrowd's flagship product line includes managed bug bounty programs, where researchers are paid per validated vulnerability according to a defined reward structure; vulnerability disclosure programs (VDPs), a lower-cost, non-monetary-reward option often used to comply with regulatory or good-practice disclosure requirements; and Penetration Testing as a Service (PTaaS), which delivers structured, scoped security assessments through the same CrowdControl platform rather than a traditional one-off consulting engagement. More recently Bugcrowd has expanded beyond pure crowdsourced testing into Attack Surface Management (ASM), which continuously discovers and maps an organization's external-facing digital assets so that security teams know what they actually need to protect. This expansion was accelerated by two acquisitions: Informer, an attack surface management company acquired in May 2024, and Mayhem Security, an AI-driven security testing firm acquired in 2025. Underpinning all of Bugcrowd's programs is its CrowdMatch technology, which algorithmically matches individual researchers to specific programs based on their skills and historical track record, and its Vulnerability Rating Taxonomy (VRT), an industry-referenced standard for classifying and prioritizing the severity of reported vulnerabilities. Bugcrowd also operates Bugcrowd University, a free educational resource for security researchers, and co-created the open-source disclose.io framework used to standardize responsible disclosure legal safe-harbor language across the industry. On the corporate side, Bugcrowd has raised roughly $90 million across an early Seed-through-Series-D funding trajectory between 2013 and 2020, and separately secured a $102 million strategic growth investment in February 2024 led by General Catalyst with participation from existing investors Rally Ventures and Costanoa Ventures, alongside additional debt financing later that year -- reporting differs across data providers on the exact cumulative total raised, but Bugcrowd remains a private, venture-backed company that has not pursued an IPO as of this research. The company reports serving customers across dozens of industries and roughly two dozen countries, with publicly referenced client names including Tesla, Atlassian, and Mastercard among others. Unlike Bugcrowd's competitor HackerOne, and much of the crowdsourced security industry generally, Bugcrowd does not publish self-serve list pricing; engagements are quoted individually based on program type, scope, and bounty pool size, with published third-party estimates suggesting entry-level VDPs starting around $10,000 per year and mid-market private bug bounty programs commonly landing in the $80,000 to $150,000 per year range once platform fees and bounty pools are combined. Bugcrowd is best suited to mid-market and enterprise security teams that want continuous, researcher-driven vulnerability discovery layered on top of, or in place of, traditional periodic penetration testing, rather than smaller organizations looking for a low-cost, self-service security tool.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd05a8911-94c8-4ded-9bc6-afc628a354e8';

