-- ── Bump.sh ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bump.sh is a modern API documentation and change-management platform that turns OpenAPI and AsyncAPI specification files into always-current, diff-aware developer documentation and API hubs, and is the current, actively developed product behind the Bump name (unrelated to the discontinued Google-acquired Bump contact-sharing app).$q$, short_description),
  pricing_model = COALESCE($q$Tiered SaaS subscription$q$, pricing_model),
  starting_price = COALESCE($q$From $50/month for the Basic plan$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$Small team, estimated fewer than 50 employees$q$, company_size),
  headquarters = COALESCE($q$Angers, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Bump.sh Review 2026: API Documentation Platform Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$What Bump.sh does, how its OpenAPI and AsyncAPI documentation platform compares, current pricing tiers, key features, pros, cons and frequently asked questions.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bump.sh is an API documentation and API change-management platform founded in 2017 in Angers, France, built around a simple idea: developer documentation should be generated automatically from an API's own machine-readable specification, and it should never silently go stale. The product name warrants a clarification up front, since 'Bump' has referred to more than one product historically: the tool covered here, now branded Bump.sh, is a distinct, currently active company and product built around API documentation and OpenAPI/AsyncAPI tooling, and it has no relationship to the unrelated Bump contact-sharing mobile app that Google acquired and subsequently shut down in 2014. Bump.sh's founder has described the product's origin in rewriting a payment API at an earlier company and being frustrated by how quickly hand-maintained API docs drifted out of sync with the actual API behavior, which shaped Bump.sh's central feature: every time a spec file changes, Bump.sh automatically diffs the new version against the previous one, publishes an updated, interactive documentation site, and can surface a human-readable changelog of exactly what changed for API consumers -- eliminating the common failure mode where documentation quietly falls behind a shipped API change. The platform supports OpenAPI 2.x and 3.x, AsyncAPI 2.x and 3.x for event-driven and asynchronous APIs, plain JSON Schema, and workflow specification formats including the OpenAPI Initiative's Arazzo standard and Bump.sh's own Flower format. Beyond individual API documentation pages, Bump.sh lets teams organize multiple OpenAPI and AsyncAPI-based docs into a single developer hub, so an organization with many services can present one unified, searchable entry point to external or internal API consumers rather than scattered, individually hosted doc sites. More recently, Bump.sh has extended its platform to compile these workflow specifications into managed Model Context Protocol (MCP) servers, positioning itself for the growing need to expose APIs to AI agents in a structured, observable way, alongside its established human-facing documentation product. Deployment is designed to fit a docs-as-code workflow: a CLI and native GitHub integration let teams deploy documentation updates automatically from CI as part of their normal release process, rather than manually uploading files to a separate CMS. Bump.sh's customer base includes companies such as MongoDB, Elastic, Lightspeed, and BigID, indicating adoption among both API-first infrastructure vendors and larger SaaS platforms. Pricing is structured as three tiers: a Basic plan at $50/month covering a limited number of API docs and internal/guest users with core OpenAPI/AsyncAPI support, CLI and GitHub integration, and API hubs; a Pro plan at $250/month that raises those limits and adds an interactive API Explorer, automatic changelogs, branch management, release rollback, deeper CI integration, and Slack notifications; and a Custom Enterprise tier with unlimited docs and users plus SSO, white-labeling, custom analytics, and a 99.99% uptime SLA. Open-source projects can apply for free access to the Pro tier, and a 14-day free trial is available. Bump.sh is best suited to API-first companies and platform teams that already maintain OpenAPI or AsyncAPI specifications as part of their development workflow and want documentation that stays automatically synchronized with the API's real behavior, rather than teams looking to hand-author documentation from scratch without an underlying machine-readable spec.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5d1a94ea-0809-4563-8930-9cce7307fe96';

