-- ── bunny.net ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$bunny.net is a developer-friendly content delivery network and edge platform offering CDN, object storage, video streaming, image optimization, DNS, and edge/serverless compute, priced on usage-based, pay-as-you-go rates rather than fixed monthly plans.$q$, short_description),
  pricing_model = COALESCE($q$Usage-based pay-as-you-go pricing across products, with a $1/month account minimum$q$, pricing_model),
  starting_price = COALESCE($q$From $0.01/GB on the Standard CDN network (North America and Europe); Volume Network from $0.005/GB for high-bandwidth use$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Ljubljana, Slovenia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$bunny.net Review 2026: CDN and Edge Platform Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$How bunny.net's CDN, storage, streaming and edge compute platform is priced, its core products, founding history, pros, cons and frequently asked questions.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$bunny.net, originally launched as BunnyCDN, is a content delivery network and edge infrastructure platform founded out of frustration with the high prices and rigid contracts of established CDN providers. The idea dates back to 2012, when founder Dejan Grofelnik Pelzel began conceptualizing a cheaper, more developer-friendly alternative, and the company was formally incorporated in 2015 in Ljubljana, Slovenia, alongside co-founders Borut Dagarin and Lovrenc Gregorcic; Ljubljana remains the company's headquarters today. What started as a single-product CDN with just eight points of presence has grown into a broader edge platform spanning content delivery, object storage, video streaming, image optimization, DNS, and edge/serverless compute, now operating well over 100 points of presence across roughly 80 countries. The unifying thread across bunny.net's product line is aggressively transparent, usage-based pricing: rather than tiered monthly subscription plans gated by feature access, nearly every bunny.net product bills by consumption, with a nominal $1/month account minimum to keep small projects viable. The core CDN product offers two pricing structures: a Standard Network with region-based per-gigabyte rates that are lowest in North America and Europe and higher in regions like South America and Asia-Pacific, and a Volume Network offering a flat global rate for very high-bandwidth projects that do not need per-region pricing granularity. Bunny Storage, the company's object storage product, is similarly billed per gigabyte per month, with a cheaper HDD tier and a faster SSD tier, and -- notably -- no charge for data transferred internally between Bunny Storage and Bunny's own CDN, which removes a common hidden cost in multi-vendor storage-plus-CDN setups. On the compute side, bunny.net offers serverless edge functions billed per request and per unit of CPU time, and a newer product called Magic Containers that lets developers run arbitrary Docker containers across bunny.net's edge network without rewriting application code for a proprietary serverless runtime, extending the platform from pure content delivery into general edge compute. Additional products round out the suite: Bunny Stream for video hosting and adaptive streaming, Bunny Optimizer for on-the-fly image resizing and compression, and a DNS product for fast, globally distributed domain resolution. Because pricing is consumption-based rather than plan-based, bunny.net does not have a small set of named subscription tiers in the way SaaS products typically do; instead, cost estimation depends on projected bandwidth, storage volume, request counts, and compute time across whichever products a customer uses. This pricing model, combined with a self-serve sign-up flow and usage-based billing without long-term contracts, has made bunny.net a popular alternative to larger, more expensive incumbent CDNs like Akamai, Fastly, and Cloudflare's paid tiers, particularly among independent developers, small and mid-sized SaaS companies, and media-heavy sites like blogs, e-commerce stores, and video platforms that are sensitive to bandwidth costs at scale.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '168f0fc4-11e6-43e9-b43d-4165c98d14f5';

